import UIKit
import WebKit

class HybridWebViewController: UIViewController {
    private var webView: WKWebView!
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupWebView()
        loadWebApp()
    }
    
    private func setupWebView() {
        let configuration = WKWebViewConfiguration()
        configuration.allowsInlineMediaPlayback = true
        configuration.mediaTypesRequiringUserActionForPlayback = []
        configuration.preferences.javaScriptEnabled = true
        
        // Add message handler
        configuration.userContentController.add(self, name: "nativeBridge")
        
        webView = WKWebView(frame: view.bounds, configuration: configuration)
        webView.autoresizingMask = [.flexibleWidth, .flexibleHeight]
        webView.navigationDelegate = self
        view.addSubview(webView)
    }
    
    private func loadWebApp() {
        guard let url = URL(string: "https://yourwebsite.com") else { return }
        let request = URLRequest(url: url)
        webView.load(request)
    }
}

extension HybridWebViewController: WKNavigationDelegate {
    func webView(_ webView: WKWebView, didFinish navigation: WKNavigation!) {
        // Web app loaded successfully
    }
}

extension HybridWebViewController: WKScriptMessageHandler {
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        guard let body = message.body as? [String: Any],
              let action = body["action"] as? String else { return }
        
        switch action {
        case "requestCameraAccess":
            requestCameraAccess()
        case "requestPushNotifications":
            requestPushNotifications()
        case "makeInAppPurchase":
            if let productId = body["productId"] as? String {
                makeInAppPurchase(productId: productId)
            }
        default:
            break
        }
    }
    
    private func requestCameraAccess() {
        AVCaptureDevice.requestAccess(for: .video) { granted in
            DispatchQueue.main.async {
                self.webView.evaluateJavaScript("cameraAccessCallback(\(granted))")
            }
        }
    }
    
    private func requestPushNotifications() {
        UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .badge, .sound]) { granted, error in
            DispatchQueue.main.async {
                self.webView.evaluateJavaScript("pushNotificationCallback(\(granted))")
            }
        }
    }
    
    private func makeInAppPurchase(productId: String) {
        // Implement in-app purchase logic
